#!/usr/bin/env python# run_dashboard.py — Architecture correcte: Yahoo Finance pour données, IBKR pour exécution## Usage:#   python3 run_dashboard.py --mode live      # IBKR paper trading (port 7497)#   python3 run_dashboard.py                  # Simulation locale#   python3 run_dashboard.py --universe liquid40import argparse, logging, syslogging.basicConfig(    level=logging.INFO,    format="%(asctime)s | %(levelname)-8s | %(name)s | %(message)s",    handlers=[        logging.StreamHandler(sys.stdout),        logging.FileHandler("logs/dashboard.log", mode="a"),    ],)logger = logging.getLogger("run_dashboard")def parse_args():    p = argparse.ArgumentParser(description="NK225 Equity Research Platform")    p.add_argument("--mode",         default="backtest", choices=["backtest", "live"])    p.add_argument("--universe",     default="full",                   choices=["full", "liquid40", "default", "custom"])    p.add_argument("--tickers",      default="")    p.add_argument("--start",        default="2022-01-01")    p.add_argument("--end",          default="2026-01-01")    p.add_argument("--host",         default="127.0.0.1")    p.add_argument("--port",         default=8050, type=int)    p.add_argument("--ibkr-port",    default=7497, type=int)    p.add_argument("--stop-loss",    default=0.06, type=float,                   help="Stop-loss automatique par position (défaut: 6%%)")    p.add_argument("--debug",        action="store_true")    # Backtest walk-forward activé PAR DÉFAUT (--no-backtest pour désactiver).    # Sans lui, le Portfolio retombe sur un equal-weight long-only trompeur    # qui reflète le bêta du marché, pas la stratégie L/S.    p.add_argument("--run-backtest", action="store_true", default=True)    p.add_argument("--no-backtest", dest="run_backtest", action="store_false")    p.add_argument("--train-months", type=int, default=12)    p.add_argument("--test-months",  type=int, default=3)    return p.parse_args()def _init_ibkr(args):    """Connexion IBKR — séparée du DataService."""    if args.mode != "live":        return None    logger.info(f"▶ Connexion IBKR port {args.ibkr_port}...")    try:        from execution.ibkr_live import IBKRLiveEngine        engine = IBKRLiveEngine(host="127.0.0.1", port=args.ibkr_port)        if engine.is_connected:            nav = engine.get_account_value()            logger.info(f"✓ IBKR paper trading connecté | NAV compte : €{nav:,.0f}")            return engine        else:            logger.warning("  IBKR connecté mais pas de réponse — fallback paper Python")    except Exception as e:        logger.warning(f"  IBKR échec ({e}) — fallback paper Python")    return Nonedef _init_paper_engine():    try:        from execution.execution_engine import PaperTradingEngine        return PaperTradingEngine(commission_bps=3.0, slippage_bps=5.0)    except Exception as e:        logger.warning(f"PaperTradingEngine: {e}")        return Nonedef _startup_backtest(ds, tickers, args):    from backtesting.backtest_engine import BacktestEngine, momentum_pipeline    logger.info("▶ Walk-forward de démarrage...")    try:        returns = ds.get_returns(tickers, args.start, args.end)        top_n   = max(5, len(tickers) // 10)        result  = BacktestEngine(            train_months=args.train_months,            test_months=args.test_months,        ).run(returns, lambda r: momentum_pipeline(r, top_n=top_n))        logger.info(f"  Backtest OK — Sharpe {result.metrics['sharpe']:.2f}")        return result    except Exception as e:        logger.warning(f"  Backtest échoué: {e}")        return Nonedef main():    args = parse_args()    # ── Univers ───────────────────────────────────────────────────    from config.universe import get_universe    tickers = ([t.strip() for t in args.tickers.split(",") if t.strip()]               if args.universe == "custom" and args.tickers               else get_universe(args.universe))    logger.info(f"Mode     : {args.mode}")    logger.info(f"Univers  : {args.universe} → {len(tickers)} tickers")    logger.info(f"Période  : {args.start} → {args.end}")    logger.info(f"Stop-loss: -{args.stop_loss*100:.0f}% par position (automatique)")    # ── IBKR (exécution seulement) ────────────────────────────────    ibkr_engine = _init_ibkr(args)    exec_engine = ibkr_engine or _init_paper_engine()    # ── DataService — TOUJOURS Yahoo Finance pour les données ─────    # IBKR est un broker, pas une source de données de recherche.    # Yahoo Finance pour les prix historiques / fondamentaux.    from data.data_service import DataService    ds = DataService(mode="backtest")  # ← FIX: jamais "live" ici    # ── Backtest optionnel ────────────────────────────────────────    backtest_result = _startup_backtest(ds, tickers, args) if args.run_backtest else None    # ── Positions IBKR au démarrage ───────────────────────────────    ibkr_positions = {}    paper_nav_eur  = 1_000_000.0   # défaut €1M    if ibkr_engine and ibkr_engine.is_connected:        try:            ibkr_positions = ibkr_engine.get_positions()            nav_eur        = ibkr_engine.get_account_value()            if nav_eur > 0:                paper_nav_eur = nav_eur            if ibkr_positions:                logger.info(f"  Positions IBKR : {ibkr_positions}")            else:                logger.info("  Aucune position ouverte dans le compte paper")        except Exception as e:            logger.warning(f"  Sync positions: {e}")    # ── DashboardDataProvider ─────────────────────────────────────    from dashboard.data_provider import DashboardDataProvider    dp = DashboardDataProvider(        data_service      = ds,        tickers           = tickers,        start             = args.start,        end               = args.end,        backtest_result   = backtest_result,        mode              = args.mode,    )    # Injecter NAV réelle et positions IBKR (compte EUR, pas de conversion)    dp.paper_nav       = paper_nav_eur    dp._ibkr_positions = ibkr_positions    dp._exec_engine    = exec_engine    dp._stop_loss_pct  = args.stop_loss    dp._fills          = []    # ── Dashboard ─────────────────────────────────────────────────    from dashboard.app import build_dashboard    app = build_dashboard(        data_provider = dp,        exec_engine   = exec_engine,        stop_loss_pct = args.stop_loss,    )    from config.settings import DASH_HOST, DASH_PORT, DASH_DEBUG    mode_str = f"IBKR PAPER port {args.ibkr_port}" if ibkr_engine else "Paper Python local"    logger.info(f"Dashboard → http://{args.host or DASH_HOST}:{args.port or DASH_PORT}  [{mode_str}]")    # threaded=False en mode live IBKR : ib_insync n'est PAS thread-safe, la    # connexion est liée au thread principal. Un serveur multi-thread ferait    # planter/bloquer les ordres passés depuis les callbacks Dash.    use_threaded = ibkr_engine is None    app.run(host=args.host or DASH_HOST, port=args.port or DASH_PORT,            debug=args.debug or DASH_DEBUG, threaded=use_threaded)if __name__ == "__main__":    main()